const body = $input.first().json.body || $input.first().json;
const { messages, model, apiKey, temperature } = body;

if (!messages || !apiKey) {
  return [{ json: { error: 'messages et apiKey requis' } }];
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://albert.api.etalab.gouv.fr/v1/chat/completions',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: model || 'albert-small',
      messages: messages,
      temperature: temperature || 0.3,
      max_tokens: 3000
    }),
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });

  if (response.statusCode >= 400) {
    return [{ json: { error: 'Albert API erreur ' + response.statusCode + ': ' + JSON.stringify(response.body).substring(0, 200) } }];
  }

  const data = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
  return [{ json: data }];

} catch(e) {
  return [{ json: { error: e.message } }];
}
